        "%type%": "esql",
        "query": "FROM metrics-unifi.device-default | WHERE @timestamp > NOW() - 10 MINUTES | STATS state = MAX(`metrics.unifi.device.state`), satisfaction = MAX(`metrics.unifi.device.satisfaction`), num_clients = MAX(`metrics.unifi.device.num_clients`) BY device_name = `observer.name`"
